-- Dogar Trading Corporation Portal — Full Database Bundle
-- ===================================================================
-- This is a complete SQLite dump of the production dataset.
-- Apply with:    sqlite3 data/dogar_trading.db < migrations/dogar_full_backup.sql
-- Or it loads automatically on first startup if data/dogar_trading.db is empty.
-- ===================================================================

BEGIN TRANSACTION;
CREATE TABLE agent_cash (
	id INTEGER NOT NULL, 
	datetime DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	agent_id INTEGER NOT NULL, 
	details VARCHAR(500), 
	debit FLOAT, 
	credit FLOAT, 
	method VARCHAR(30), 
	ref_id VARCHAR(100), 
	user_id INTEGER, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(agent_id) REFERENCES agents (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE agents (
	id INTEGER NOT NULL, 
	name VARCHAR(255) NOT NULL, 
	company_name VARCHAR(255), 
	phone VARCHAR(50), 
	mobile VARCHAR(50), 
	email VARCHAR(150), 
	address TEXT, 
	city VARCHAR(100), 
	status VARCHAR(30), 
	notes TEXT, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE audit_logs (
	id INTEGER NOT NULL, 
	entity_type VARCHAR(40) NOT NULL, 
	entity_id INTEGER, 
	action VARCHAR(40) NOT NULL, 
	actor_user_id INTEGER, 
	actor_name VARCHAR(150), 
	summary VARCHAR(500), 
	before_json JSON, 
	after_json JSON, 
	ip_address VARCHAR(64), 
	user_agent VARCHAR(255), 
	occurred_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(actor_user_id) REFERENCES users (id)
);
CREATE TABLE candidate_assignments (
	id INTEGER NOT NULL, 
	candidate_id INTEGER NOT NULL, 
	job_category_id INTEGER NOT NULL, 
	status VARCHAR(30), 
	embassy VARCHAR(150), 
	assigned_by_id INTEGER, 
	assigned_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	unassigned_at DATETIME, 
	notes TEXT, 
	PRIMARY KEY (id), 
	FOREIGN KEY(candidate_id) REFERENCES candidates (id), 
	FOREIGN KEY(job_category_id) REFERENCES job_categories (id), 
	FOREIGN KEY(assigned_by_id) REFERENCES users (id)
);
CREATE TABLE candidate_document_checklist (
	id INTEGER NOT NULL, 
	candidate_id INTEGER NOT NULL, 
	document_key VARCHAR(50) NOT NULL, 
	received INTEGER, 
	received_at DATETIME, 
	received_by VARCHAR(150), 
	notes TEXT, 
	PRIMARY KEY (id), 
	FOREIGN KEY(candidate_id) REFERENCES candidates (id)
);
CREATE TABLE candidate_wizard_states (
	id INTEGER NOT NULL, 
	candidate_id INTEGER, 
	job_category_id INTEGER, 
	current_step INTEGER, 
	total_steps INTEGER, 
	is_finalized INTEGER, 
	step_data JSON, 
	created_by_id INTEGER, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	finalized_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(candidate_id) REFERENCES candidates (id), 
	FOREIGN KEY(job_category_id) REFERENCES job_categories (id), 
	FOREIGN KEY(created_by_id) REFERENCES users (id)
);
CREATE TABLE candidates (
	id INTEGER NOT NULL, 
	full_name VARCHAR(255) NOT NULL, 
	name_arabic VARCHAR(255), 
	mother_name VARCHAR(255), 
	father_name VARCHAR(255), 
	father_name_arabic VARCHAR(255), 
	gender VARCHAR(10), 
	marital_status VARCHAR(20), 
	religion VARCHAR(30), 
	date_of_birth DATE, 
	place_of_birth VARCHAR(100), 
	place_of_birth_arabic VARCHAR(100), 
	nationality VARCHAR(50), 
	address TEXT, 
	phone VARCHAR(30), 
	tehsil VARCHAR(100), 
	district VARCHAR(100), 
	province VARCHAR(100), 
	photo VARCHAR(255), 
	passport_no VARCHAR(50), 
	passport_issue_date DATE, 
	passport_expiry_date DATE, 
	issuing_authority VARCHAR(100), 
	issuing_authority_arabic VARCHAR(100), 
	passport_issue_place VARCHAR(100), 
	cnic VARCHAR(30), 
	nadra_token_no VARCHAR(50), 
	permission_no VARCHAR(100), 
	permission_date DATE, 
	qualification VARCHAR(150), 
	age_employee INTEGER, 
	profession VARCHAR(100), 
	salary NUMERIC(12, 2), 
	next_of_kin_name VARCHAR(255), 
	next_of_kin_nic VARCHAR(30), 
	next_of_kin_relation VARCHAR(50), 
	protector_no VARCHAR(50), 
	protector_date DATE, 
	medical_center VARCHAR(150), 
	gamca_number VARCHAR(50), 
	medical_date DATE, 
	medical_consignment_no VARCHAR(50), 
	medical_send_date DATE, 
	medical_courier_name VARCHAR(100), 
	e_number VARCHAR(50), 
	date_of_departure DATE, 
	flight_no VARCHAR(50), 
	destination VARCHAR(100), 
	ticket_no VARCHAR(50), 
	visa_stamp_date DATE, 
	ticket_included VARCHAR(10), 
	accommodation_allowance VARCHAR(50), 
	food_allowance VARCHAR(50), 
	slot_notes TEXT, 
	price NUMERIC(12, 2), 
	email VARCHAR(150), 
	status VARCHAR(30), 
	notes TEXT, 
	created_by_id INTEGER, 
	updated_by_id INTEGER, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(created_by_id) REFERENCES users (id), 
	FOREIGN KEY(updated_by_id) REFERENCES users (id)
);
