CREATE TABLE cities (
	id INTEGER NOT NULL, 
	name VARCHAR(150) NOT NULL, 
	province VARCHAR(100), 
	country VARCHAR(100), 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE client_contacts (
	id INTEGER NOT NULL, 
	client_id INTEGER NOT NULL, 
	name VARCHAR(150) NOT NULL, 
	designation VARCHAR(100), 
	email VARCHAR(150), 
	phone VARCHAR(50), 
	is_primary BOOLEAN, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(client_id) REFERENCES clients (id)
);
CREATE TABLE client_statements (
	id INTEGER NOT NULL, 
	client_id INTEGER NOT NULL, 
	demand_id INTEGER, 
	entry_type VARCHAR(20), 
	reference VARCHAR(100), 
	description TEXT, 
	debit NUMERIC(14, 2), 
	credit NUMERIC(14, 2), 
	payment_method VARCHAR(40), 
	receipt_no VARCHAR(50), 
	received_by VARCHAR(150), 
	entry_date DATE DEFAULT (CURRENT_DATE) NOT NULL, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(client_id) REFERENCES clients (id), 
	FOREIGN KEY(demand_id) REFERENCES demands (id)
);
CREATE TABLE clients (
	id INTEGER NOT NULL, 
	company_name VARCHAR(255) NOT NULL, 
	client_type VARCHAR(30), 
	status VARCHAR(30), 
	license_no VARCHAR(100), 
	email VARCHAR(150), 
	phone VARCHAR(50), 
	sponsor_name VARCHAR(255), 
	sponsor_name_arabic VARCHAR(255), 
	sponsor_address TEXT, 
	sponsor_address_arabic TEXT, 
	sponsor_phone VARCHAR(50), 
	sponsor_alt_phone VARCHAR(50), 
	sponsor_id VARCHAR(100), 
	street TEXT, 
	city VARCHAR(100), 
	state VARCHAR(100), 
	country VARCHAR(100), 
	address TEXT, 
	contact_person VARCHAR(150), 
	opening_balance NUMERIC(14, 2), 
	opening_balance_direction VARCHAR(20), 
	opening_balance_date DATE, 
	notes TEXT, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE company_settings (
	id INTEGER NOT NULL, 
	company_name VARCHAR(200), 
	company_name_arabic VARCHAR(200), 
	oep_license_number VARCHAR(50), 
	owner_name VARCHAR(150), 
	address TEXT, 
	address_arabic TEXT, 
	phone VARCHAR(50), 
	mobile VARCHAR(50), 
	fax VARCHAR(50), 
	email VARCHAR(150), 
	website VARCHAR(150), 
	subdomain VARCHAR(50), 
	slug VARCHAR(50), 
	file_prefix VARCHAR(20), 
	starting_point INTEGER, 
	status VARCHAR(20), 
	"plan" VARCHAR(100), 
	expiry_date DATE, 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE contacts (
	id INTEGER NOT NULL, 
	name VARCHAR(150) NOT NULL, 
	company VARCHAR(150), 
	email VARCHAR(150), 
	phone VARCHAR(50), 
	note TEXT, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE demands (
	id INTEGER NOT NULL, 
	file_number VARCHAR(50) NOT NULL, 
	demand_code VARCHAR(50), 
	client_id INTEGER NOT NULL, 
	receiving_date DATE, 
	permission_no VARCHAR(100), 
	permission_date DATE, 
	reference VARCHAR(150), 
	sponsor_name VARCHAR(255), 
	sponsor_name_arabic VARCHAR(255), 
	sponsor_address TEXT, 
	sponsor_address_arabic TEXT, 
	sponsor_phone VARCHAR(50), 
	sponsor_alt_phone VARCHAR(50), 
	visa_number VARCHAR(100), 
	bataka_number VARCHAR(100), 
	visa_issue_date DATE, 
	visa_issue_date_hijri VARCHAR(50), 
	country VARCHAR(100), 
	embassy VARCHAR(150), 
	document_count INTEGER, 
	expiry_date DATETIME, 
	visa_quota INTEGER, 
	benefits TEXT, 
	created_by_id INTEGER, 
	updated_by_id INTEGER, 
	status VARCHAR(30), 
	notes TEXT, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(client_id) REFERENCES clients (id), 
	FOREIGN KEY(created_by_id) REFERENCES users (id), 
	FOREIGN KEY(updated_by_id) REFERENCES users (id)
);
CREATE TABLE depositors (
	id INTEGER NOT NULL, 
	first_name VARCHAR(100) NOT NULL, 
	last_name VARCHAR(100), 
	full_name VARCHAR(200), 
	cnic VARCHAR(30), 
	mobile VARCHAR(50), 
	address TEXT, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE document_fields (
	id INTEGER NOT NULL, 
	template_id INTEGER NOT NULL, 
	label VARCHAR(150) NOT NULL, 
	field_key VARCHAR(100) NOT NULL, 
	field_type VARCHAR(30), 
	static_value TEXT, 
	x FLOAT NOT NULL, 
	y FLOAT NOT NULL, 
	width FLOAT, 
	height FLOAT, 
	font_size FLOAT, 
	font_bold BOOLEAN, 
	font_italic BOOLEAN, 
	color VARCHAR(10), 
	align VARCHAR(10), 
	page INTEGER, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), meta JSON DEFAULT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(template_id) REFERENCES document_templates (id)
);
CREATE TABLE document_templates (
	id INTEGER NOT NULL, 
	name VARCHAR(255) NOT NULL, 
	description TEXT, 
	category VARCHAR(50), 
	data_source VARCHAR(50), 
	background_image VARCHAR(255), 
	page_width FLOAT, 
	page_height FLOAT, 
	is_active BOOLEAN, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE embassies (
	id INTEGER NOT NULL, 
	name VARCHAR(150) NOT NULL, 
	country VARCHAR(100), 
	city VARCHAR(100), 
	address TEXT, 
	phone VARCHAR(50), 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE generated_documents (
	id INTEGER NOT NULL, 
	template_id INTEGER NOT NULL, 
	record_id INTEGER, 
	file_path VARCHAR(500), 
	generated_by INTEGER, 
	generated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(template_id) REFERENCES document_templates (id), 
	FOREIGN KEY(generated_by) REFERENCES users (id)
);
CREATE TABLE job_categories (
	id INTEGER NOT NULL, 
	demand_id INTEGER NOT NULL, 
	trade VARCHAR(150) NOT NULL, 
	quantity INTEGER, 
	salary FLOAT, 
	salary_currency VARCHAR(10), 
	contract_years INTEGER, 
	notes TEXT, 
	custom_fields JSON, 
	created_by_id INTEGER, 
	updated_by_id INTEGER, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(demand_id) REFERENCES demands (id), 
	FOREIGN KEY(created_by_id) REFERENCES users (id), 
	FOREIGN KEY(updated_by_id) REFERENCES users (id)
);
CREATE TABLE login_history (
	id INTEGER NOT NULL, 
	email VARCHAR(150) NOT NULL, 
	status VARCHAR(20), 
	ip_address VARCHAR(64), 
	user_agent TEXT, 
	occurred_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE medical_centers (
	id INTEGER NOT NULL, 
	name VARCHAR(200) NOT NULL, 
	city VARCHAR(100), 
	address TEXT, 
	phone VARCHAR(50), 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE password_reset_tokens (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	email VARCHAR(150) NOT NULL, 
	token VARCHAR(80) NOT NULL, 
	expires_at DATETIME NOT NULL, 
	used_at DATETIME, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE roles (
	id INTEGER NOT NULL, 
	name VARCHAR(50) NOT NULL, 
	description TEXT, 
	is_system BOOLEAN, 
	permissions TEXT, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
CREATE TABLE service_charges (
	id INTEGER NOT NULL, 
	name VARCHAR(150) NOT NULL, 
	amount NUMERIC(12, 2), 
	description TEXT, 
	is_active BOOLEAN, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE support_messages (
	id INTEGER NOT NULL, 
	name VARCHAR(150), 
	email VARCHAR(150), 
	phone VARCHAR(50), 
	subject VARCHAR(255), 
	message TEXT, 
	status VARCHAR(20), 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE TABLE tenants (
	id INTEGER NOT NULL, 
	slug VARCHAR(50) NOT NULL, 
	company_name VARCHAR(200) NOT NULL, 
	short_name VARCHAR(50) NOT NULL, 
	subtitle VARCHAR(150), 
	primary_color VARCHAR(20), 
	logo_filename VARCHAR(255), 
	db_path VARCHAR(500) NOT NULL, 
	features JSON NOT NULL, 
	contact_name VARCHAR(150), 
	contact_email VARCHAR(150), 
	contact_phone VARCHAR(50), 
	status VARCHAR(20), 
	"plan" VARCHAR(30), 
	admin_email VARCHAR(150), 
	admin_password_set BOOLEAN, 
	notes TEXT, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE users (
	id INTEGER NOT NULL, 
	username VARCHAR(50), 
	name VARCHAR(100) NOT NULL, 
	email VARCHAR(150) NOT NULL, 
	password_hash VARCHAR(255) NOT NULL, 
	role VARCHAR(20), 
	is_active BOOLEAN, 
	phone VARCHAR(30), 
	photo VARCHAR(255), 
	designation VARCHAR(120), 
	bio VARCHAR(500), 
	theme VARCHAR(50), 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	updated_at DATETIME DEFAULT (CURRENT_TIMESTAMP), must_change_password BOOLEAN DEFAULT 0, 
	PRIMARY KEY (id)
);
CREATE TABLE visa_categories (
	id INTEGER NOT NULL, 
	name VARCHAR(150) NOT NULL, 
	code VARCHAR(50), 
	description TEXT, 
	is_active BOOLEAN, 
	created_at DATETIME DEFAULT (CURRENT_TIMESTAMP), 
	PRIMARY KEY (id)
);
CREATE UNIQUE INDEX ix_users_email ON users (email);
CREATE UNIQUE INDEX ix_users_username ON users (username);
CREATE INDEX ix_users_id ON users (id);
